import { GiftedChat, IMessage, User } from 'react-native-gifted-chat';
import Anthropic from '@anthropic-ai/sdk';

const CLAUDE_USER: User = { _id: 'claude', name: 'Claude', avatar: undefined };
const ME: User = { _id: 'me' };

// Convert GiftedChat messages -> Anthropic API messages
function toApiMessages(
  gcMessages: IMessage[]
): Anthropic.MessageParam[] {
  return [...gcMessages]
    .reverse()                   // GiftedChat stores newest-first
    .filter(m => typeof m.text === 'string')
    .map(m => ({
      role: m.user._id === 'me' ? 'user' : 'assistant',
      content: m.text as string,
    }));
}

import React, { useState, useCallback } from 'react';
import { View, ActivityIndicator } from 'react-native';
import { GiftedChat, IMessage } from 'react-native-gifted-chat';
import Anthropic from '@anthropic-ai/sdk';

const client = new Anthropic({ apiKey: process.env.EXPO_PUBLIC_ANTHROPIC_KEY! });

export default function ClaudeChat() {
  const [messages, setMessages] = useState<IMessage[]>([]);
  const [streaming, setStreaming] = useState(false);

  const onSend = useCallback(async (newMessages: IMessage[]) => {
    // 1. Append the user message immediately
    const withUser = GiftedChat.append(messages, newMessages);
    setMessages(withUser);

    // 2. Create a placeholder for the streaming reply
    const placeholderId = Date.now().toString();
    const placeholder: IMessage = {
      _id: placeholderId,
      text: '',
      createdAt: new Date(),
      user: CLAUDE_USER,
    };
    setMessages(prev => GiftedChat.append(prev, [placeholder]));
    setStreaming(true);

    // 3. Stream and update the placeholder in place
    try {
      const stream = client.messages.stream({
        model: 'claude-opus-4-8',
        max_tokens: 1024,
        messages: toApiMessages(withUser),
      });

      for await (const event of stream) {
        if (
          event.type === 'content_block_delta' &&
          event.delta.type === 'text_delta'
        ) {
          const chunk = event.delta.text;
          setMessages(prev =>
            prev.map(m =>
              m._id === placeholderId
                ? { ...m, text: m.text + chunk }
                : m
            )
          );
        }
      }
    } finally {
      setStreaming(false);
    }
  }, [messages]);

  return (
    <GiftedChat
      messages={messages}
      onSend={onSend}
      user={ME}
      renderFooter={() =>
        streaming ? <ActivityIndicator style={{ margin: 8 }} /> : null
      }
      inverted       // GiftedChat keeps newest at bottom this way
    />
  );
}

import Markdown from 'react-native-markdown-display';
import { Bubble } from 'react-native-gifted-chat';

function MarkdownBubble(props: any) {
  const isAssistant = props.currentMessage?.user?._id === 'claude';
  if (isAssistant) {
    return (
      <Bubble
        {...props}
        renderMessageText={() => (
          <Markdown
            style={{ body: { color: '#111827', padding: 8 } }}
          >
            {props.currentMessage.text}
          </Markdown>
        )}
      />
    );
  }
  return <Bubble {...props} />;
}

// In <GiftedChat>:
// renderBubble={(props) => <MarkdownBubble {...props} />}

type Role = 'user' | 'assistant';

interface Message {
  id: string;
  role: Role;
  text: string;        // grows incrementally during streaming
  streaming: boolean;  // shows cursor while true
}

// Seed with a system message if needed
const [messages, setMessages] = useState<Message[]>([]);
const [input, setInput] = useState('');

import {
  FlatList, View, Text, TextInput, Pressable,
  KeyboardAvoidingView, Platform, StyleSheet,
} from 'react-native';

export default function CustomChatScreen() {
  // ... state from above

  return (
    <KeyboardAvoidingView
      style={{ flex: 1 }}
      behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
      keyboardVerticalOffset={90}
    >
      <FlatList
        data={messages}
        keyExtractor={m => m.id}
        renderItem={({ item }) => <MessageBubble message={item} />}
        // Keeps the latest message at the bottom
        contentContainerStyle={{ flexGrow: 1, justifyContent: 'flex-end' }}
        // Auto-scroll on new message
        onContentSizeChange={() =>
          flatListRef.current?.scrollToEnd({ animated: true })
        }
      />
      <InputBar input={input} onChange={setInput} onSend={handleSend} />
    </KeyboardAvoidingView>
  );
}

function MessageBubble({ message }: { message: Message }) {
  const isUser = message.role === 'user';
  const displayText = message.streaming
    ? message.text + '▋'   // blinking block cursor
    : message.text;

  return (
    <View style={[
      styles.bubble,
      isUser ? styles.userBubble : styles.assistantBubble
    ]}>
      <Text style={isUser ? styles.userText : styles.assistantText}>
        {displayText}
      </Text>
    </View>
  );
}

const styles = StyleSheet.create({
  bubble: {
    maxWidth: '80%', borderRadius: 16,
    marginVertical: 4, paddingHorizontal: 14, paddingVertical: 10,
  },
  userBubble: { alignSelf: 'flex-end', backgroundColor: '#6366f1' },
  assistantBubble: { alignSelf: 'flex-start', backgroundColor: '#f3f4f6' },
  userText: { color: '#fff', fontSize: 15 },
  assistantText: { color: '#111827', fontSize: 15 },
});

const abortRef = useRef<AbortController | null>(null);

async function handleSend() {
  if (!input.trim()) return;

  const userMsg: Message = { id: Date.now().toString(), role: 'user', text: input.trim(), streaming: false };
  const assistantId = (Date.now() + 1).toString();
  const assistantMsg: Message = { id: assistantId, role: 'assistant', text: '', streaming: true };

  setMessages(prev => [...prev, userMsg, assistantMsg]);
  setInput('');

  const controller = new AbortController();
  abortRef.current = controller;

  try {
    // Build full conversation history
    const history = messages
      .filter(m => !m.streaming)
      .map(m => ({ role: m.role as 'user' | 'assistant', content: m.text }));
    history.push({ role: 'user', content: userMsg.text });

    const stream = client.messages.stream(
      { model: 'claude-opus-4-8', max_tokens: 1024, messages: history },
      { signal: controller.signal }
    );

    for await (const event of stream) {
      if (
        event.type === 'content_block_delta' &&
        event.delta.type === 'text_delta'
      ) {
        const chunk = event.delta.text;
        setMessages(prev =>
          prev.map(m =>
            m.id === assistantId
              ? { ...m, text: m.text + chunk }
              : m
          )
        );
      }
    }
  } catch (err: any) {
    if (err.name !== 'AbortError') throw err;
  } finally {
    setMessages(prev =>
      prev.map(m =>
        m.id === assistantId ? { ...m, streaming: false } : m
      )
    );
    abortRef.current = null;
  }
}

function InputBar({ input, onChange, onSend, isStreaming, onStop }) {
  return (
    <View style={styles.inputRow}>
      <TextInput
        style={styles.textInput}
        value={input}
        onChangeText={onChange}
        placeholder="Message Claude..."
        multiline
        returnKeyType="send"
        onSubmitEditing={onSend}
      />
      {isStreaming ? (
        <Pressable onPress={onStop} style={styles.stopBtn}>
          <Text style={{ color: '#fff', fontWeight: '700' }}>Stop</Text>
        </Pressable>
      ) : (
        <Pressable onPress={onSend} style={styles.sendBtn}>
          <Text style={{ color: '#fff', fontWeight: '700' }}>Send</Text>
        </Pressable>
      )}
    </View>
  );
}

// In the parent component:
function handleStop() {
  abortRef.current?.abort();
}

function buildHistory(
  messages: Message[],
  systemPrompt?: string
): Anthropic.MessageParam[] {
  const params: Anthropic.MessageParam[] = messages
    .filter(m => !m.streaming && m.text.length > 0)
    .map(m => ({ role: m.role, content: m.text }));
  return params;
}

// Usage:
const stream = client.messages.stream({
  model: 'claude-opus-4-8',
  max_tokens: 1024,
  system: 'You are a helpful assistant.',
  messages: buildHistory(messages),
});
